aker_name":"bwillans"},{"text":"James did.","index":104,"end_time":309.48,"speaker_id":0,"start_time":308.8,"speaker_name":"bwillans"},{"text":"But same.","index":105,"end_time":310.6,"speaker_id":0,"start_time":309.8,"speaker_name":"bwillans"},{"text":"Which means it''s me.","index":106,"end_time":312.04,"speaker_id":0,"start_time":311,"speaker_name":"bwillans"},{"text":"Right.","index":107,"end_time":312.36,"speaker_id":0,"start_time":312.04,"speaker_name":"bwillans"},{"text":"So I wasn''t sure which form to put in for on demand so that it was captured in HubSpot and then Salesforce.","index":108,"end_time":319.4,"speaker_id":0,"start_time":312.36,"speaker_name":"bwillans"},{"text":"So that''s an old form.","index":109,"end_time":320.6,"speaker_id":0,"start_time":319.4,"speaker_name":"bwillans"},{"text":"So just.","index":110,"end_time":321.88,"speaker_id":0,"start_time":321.32,"speaker_name":"bwillans"},{"text":"Or, you know, let me know how to do it through a loom or something.","index":111,"end_time":326.04,"speaker_id":0,"start_time":322.28,"speaker_name":"bwillans"},{"text":"Happy to do it.","index":112,"end_time":326.72,"speaker_id":0,"start_time":326.04,"speaker_name":"bwillans"},{"text":"But we want to make sure that it''s captured.","index":113,"end_time":328.32,"speaker_id":0,"start_time":326.72,"speaker_name":"bwillans"},{"text":"Yeah, yeah.","index":114,"end_time":329.36,"speaker_id":2,"start_time":328.32,"speaker_name":"Guille Santana"},{"text":"So the process is simple.","index":115,"end_time":331.44,"speaker_id":2,"start_time":329.36,"speaker_name":"Guille Santana"},{"text":"We just need to Change the thank you page.","index":116,"end_time":335.52,"speaker_id":2,"start_time":331.6,"speaker_name":"Guille Santana"},{"text":"So you guys build a thank you page with the video.","index":117,"end_time":338.16,"speaker_id":2,"start_time":335.6,"speaker_name":"Guille Santana"},{"text":"And I believe a lot of little text over there to make them on demand is just go to the form on HubSpot and change the page.","index":118,"end_time":348.32,"speaker_id":2,"start_time":338.72,"speaker_name":"Guille Santana"},{"text":"I am happy to do that for you.","index":119,"end_time":350.24,"speaker_id":2,"start_time":348.4,"speaker_name":"Guille Santana"},{"text":"Or I can do a loom video if you ever need to do it.","index":120,"end_time":354.72,"speaker_id":2,"start_time":350.56,"speaker_name":"Guille Santana"},{"text":"I''m not clear.","index":121,"end_time":358.07,"speaker_id":0,"start_time":357.63,"speaker_name":"bwillans"},{"text":"We''re talking about the same thing.","index":122,"end_time":359.63,"speaker_id":0,"start_time":358.07,"speaker_name":"bwillans"},{"text":"So they.","index":123,"end_time":360.43,"speaker_id":0,"start_time":359.87,"speaker_name":"bwillans"},{"text":"And maybe we are.","index":124,"end_time":361.27,"speaker_id":0,"start_time":360.51,"speaker_name":"bwillans"},{"text":"And it''s just me and I need more coffee.","index":125,"end_time":362.79,"speaker_id":0,"start_time":361.27,"speaker_name":"bwillans"},{"text":"So when we switched it over, it says view the video, and there''s a form there.","index":126,"end_time":367.31,"speaker_id":0,"start_time":362.79,"speaker_name":"bwillans"},{"text":"That form is different.","index":127,"end_time":369.79,"speaker_id":0,"start_time":367.55,"speaker_name":"bwillans"},{"text":"Like, it doesn''t have the opt in.","index":128,"end_time":371.95,"speaker_id":0,"start_time":369.95,"speaker_name":"bwillans"},{"text":"It doesn''t like it.","index":129,"end_time":373.15,"speaker_id":0,"start_time":372.11,"speaker_name":"bwillans"},{"text":"It seems like it''s the old Marketo form.","index":130,"end_time":375.91,"speaker_id":0,"start_time":373.15,"speaker_name":"bwillans"},{"text":"Now.","index":131,"end_time":376.19,"speaker_id":0,"start_time":375.91,"speaker_name":"bwillans"},{"text":"I could be wrong.","index":132,"end_time":377.15,"speaker_id":0,"start_time":376.19,"speaker_name":"bwillans"},{"text":"So they have to fill out their contacts.","index":133,"end_time":378.99,"speaker_id":0,"start_time":377.31,"speaker_name":"bwillans"},{"text":"I want to make sure that it''s going in a HubSpot and then connecting.","index":134,"end_time":382.34,"speaker_id":0,"start_time":378.99,"speaker_name":"bwillans"},{"text":"Okay.","index":135,"end_time":382.7,"speaker_id":0,"start_time":382.34,"speaker_name":"bwillans"},{"text":"Is that.","index":136,"end_time":383.14,"speaker_id":0,"start_time":382.7,"speaker_name":"bwillans"},{"text":"Is that correct?","index":137,"end_time":384.26,"speaker_id":0,"start_time":383.14,"speaker_name":"bwillans"},{"text":"The thing is, we didn''t really need to change the form.","index":138,"end_time":389.22,"speaker_id":2,"start_time":385.86,"speaker_name":"Guille Santana"},{"text":"Okay.","index":139,"end_time":390.42,"speaker_id":0,"start_time":389.86,"speaker_name":"bwillans"},{"text":"We needed to change the thank you page.","index":140,"end_time":394.42,"speaker_id":2,"start_time":390.74,"speaker_name":"Guille Santana"},{"text":"Right.","index":141,"end_time":395.06,"speaker_id":2,"start_time":394.66,"speaker_name":"Guille Santana"},{"text":"But I don''t know if you want to do that or for upcoming webinars.","index":142,"end_time":401.9,"speaker_id":2,"start_time":396.82,"speaker_name":"Guille Santana"},{"text":"Do you want to use the Marketo form that you used?","index":143,"end_time":404.66,"speaker_id":2,"start_time":401.9,"speaker_name":"Guille Santana"},{"text":"No, we don''t want any Marketo forms.","index":144,"end_time":407.38,"speaker_id":0,"start_time":405.3,"speaker_name":"bwillans"},{"text":"That''s my whole point, is that marketo''s being cut off at the end.","index":145,"end_time":411.81,"speaker_id":0,"start_time":407.7,"speaker_name":"bwillans"},{"text":"Like, we.","index":146,"end_time":412.25,"speaker_id":0,"start_time":411.81,"speaker_name":"bwillans"},{"text":"We just need it to be a HubSpot form and flow appropriately.","index":147,"end_time":414.93,"speaker_id":0,"start_time":412.25,"speaker_name":"bwillans"},{"text":"And whatever I need to do to do that.","index":148,"end_time":416.85,"speaker_id":0,"start_time":414.93,"speaker_name":"bwillans"},{"text":"If it''s the thank you page or the form, I just.","index":149,"end_time":419.53,"speaker_id":0,"start_time":416.85,"speaker_name":"bwillans"},{"text":"We have a lot upcoming and just want to make sure that we''re doing the right thing.","index":150,"end_time":424.09,"speaker_id":0,"start_time":419.53,"speaker_name":"bwillans"},{"text":"Yeah, yeah, yeah, yeah.","index":151,"end_time":426.01,"speaker_id":2,"start_time":424.65,"speaker_name":"Guille Santana"},{"text":"So I can switch those for you and I can.","index":152,"end_time":429.05,"speaker_id":2,"start_time":427.05,"speaker_name":"Guille Santana"},{"text":"Or I can.","index":153,"end_time":429.69,"speaker_id":2,"start_time":429.05,"speaker_name":"Guille Santana"},{"text":"I''ll make a video for you if you ever need to do it.","index":154,"end_time":432.65,"speaker_id":2,"start_time":430.33,"speaker_name":"Guille Santana"},{"text":"That''d be great.","index":155,"end_time":433.93,"speaker_id":0,"start_time":433.13,"speaker_name":"bwillans"},{"text":"Yeah.","index":156,"end_time":434.37,"speaker_id":0,"start_time":433.93,"speaker_name":"bwillans"},{"text":"Because we.","index":157,"end_time":434.69,"speaker_id":0,"start_time":434.37,"speaker_name":"bwillans"},{"text":"We''re gonna have three or four of these a month, and I don''t want to keep pinging youg going.","index":158,"end_time":438.01,"speaker_id":0,"start_time":434.69,"speaker_name":"bwillans"},{"text":"Hey, can you help?","index":159,"end_time":438.57,"speaker_id":0,"start_time":438.01,"speaker_name":"bwillans"},{"text":"Yeah.","index":160,"end_time":438.81,"speaker_id":1,"start_time":438.57,"speaker_name":"Colin Costigan"},{"text":"So we''ll.","index":161,"end_time":439.05,"speaker_id":0,"start_time":438.81,"speaker_name":"bwillans"},{"text":"We''ll do a full sweep on these, and then we''ll record one for you.","index":162,"end_time":442.21,"speaker_id":1,"start_time":439.05,"speaker_name":"Colin Costigan"},{"text":"So that, you know, that''d be great.","index":163,"end_time":443.93,"speaker_id":0,"start_time":442.21,"speaker_name":"bwillans"},{"text":"Thank you so much, guys.","index":164,"end_time":444.89,"speaker_id":0,"start_time":443.93,"speaker_name":"bwillans"},{"text":"Appreciate it.","index":165,"end_time":445.53,"speaker_id":0,"start_time":444.89,"speaker_name":"bwillans"},{"text":"Yep.","index":166,"end_time":447.69,"speaker_id":2,"start_time":447.13,"speaker_name":"Guille Santana"},{"text":"And I guess that''s.","index":167,"end_time":450.41,"speaker_id":2,"start_time":448.57,"speaker_name":"Guille Santana"},{"text":"Oh, no.","index":168,"end_time":451.29,"speaker_id":2,"start_time":450.65,"speaker_name":"Guille Santana"},{"text":"I just wanted to ask you if we are good to start updating, like, the older forms, like toolkits, on demand, webinars, stuff like that to HubSpot.","index":169,"end_time":460.37,"speaker_id":2,"start_time":452.65,"speaker_name":"Guille Santana"},{"text":"Yeah, you can go for it.","index":170,"end_time":461.57,"speaker_id":0,"start_time":460.37,"speaker_name":"bwillans"},{"text":"You can update everything now.","index":171,"end_time":463.05,"speaker_id":0,"start_time":461.57,"speaker_name":"bwillans"},{"text":"Got it.","index":172,"end_time":463.69,"speaker_id":2,"start_time":463.21,"speaker_name":"Guille Santana"},{"text":"Awesome.","index":173,"end_time":464.17,"speaker_id":1,"start_time":463.69,"speaker_name":"Colin Costigan"},{"text":"Awesome.","index":174,"end_time":465.61,"speaker_id":0,"start_time":464.97,"speaker_name":"bwillans"},{"text":"Thank you.","index":175,"end_time":466.33,"speaker_id":0,"start_time":465.69,"speaker_name":"bwillans"},{"text":"I guess that''s it.","index":176,"end_time":468.99,"speaker_id":2,"start_time":468.03,"speaker_name":"Guille Santana"},{"text":"Yeah.","index":177,"end_time":471.03,"speaker_id":0,"start_time":470.67,"speaker_name":"bwillans"},{"text":"I''ll go through Pulse today and.","index":178,"end_time":472.71,"speaker_id":0,"start_time":471.03,"speaker_name":"bwillans"},{"text":"Wow, that was quick.","index":179,"end_time":473.55,"speaker_id":0,"start_time":472.71,"speaker_name":"bwillans"},{"text":"And.","index":180,"end_time":473.83,"speaker_id":0,"start_time":473.55,"speaker_name":"bwillans"},{"text":"But Good stuff.","index":181,"end_time":474.75,"speaker_id":0,"start_time":473.83,"speaker_name":"bwillans"},{"text":"Like, awesome.","index":182,"end_time":475.39,"speaker_id":0,"start_time":474.75,"speaker_name":"bwillans"},{"text":"And just one thing, I guess, for all of you, I met with Tristan.","index":183,"end_time":481.23,"speaker_id":0,"start_time":475.39,"speaker_name":"bwillans"},{"text":"Colin, thank you so much for working through the ABM scoring.","index":184,"end_time":486.15,"speaker_id":0,"start_time":481.55,"speaker_name":"bwillans"},{"text":"And it looks really good.","index":185,"end_time":487.71,"speaker_id":0,"start_time":486.15,"speaker_name":"bwillans"},{"text":"The only thing, I don''t know if Tristan talked to you.","index":186,"end_time":490.07,"speaker_id":0,"start_time":487.71,"speaker_name":"bwillans"},{"text":"I don''t know that it''s enough.","index":187,"end_time":491.31,"speaker_id":0,"start_time":490.07,"speaker_name":"bwillans"},{"text":"When I say enough, I don''t know that.","index":188,"end_time":493.51,"speaker_id":0,"start_time":491.71,"speaker_name":"bwillans"},{"text":"Yeah.","index":189,"end_time":494.39,"speaker_id":0,"start_time":494.07,"speaker_name":"bwillans"},{"text":"He said you wanted some extra padding in there.","index":190,"end_time":496.07,"speaker_id":1,"start_time":494.39,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":191,"end_time":496.63,"speaker_id":1,"start_time":496.15,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":192,"end_time":497.43,"speaker_id":0,"start_time":497.03,"speaker_name":"bwillans"},{"text":"Because of stuff like this.","index":193,"end_time":498.63,"speaker_id":0,"start_time":497.43,"speaker_name":"bwillans"},{"text":"Right.","index":194,"end_time":498.87,"speaker_id":0,"start_time":498.63,"speaker_name":"bwillans"},{"text":"It''s like, hey, we just.","index":195,"end_time":501.19,"speaker_id":0,"start_time":498.87,"speaker_name":"bwillans"},{"text":"I''m going to throw some padding in there and then we''ll get that sorted on Monday when Vinny can sign it off.","index":196,"end_time":506.27,"speaker_id":0,"start_time":501.35,"speaker_name":"bwillans"},{"text":"Yeah.","index":197,"end_time":506.67,"speaker_id":0,"start_time":506.27,"speaker_name":"bwillans"},{"text":"All good, though.","index":198,"end_time":507.35,"speaker_id":0,"start_time":506.67,"speaker_name":"bwillans"},{"text":"Yep.","index":199,"end_time":508.15,"speaker_id":0,"start_time":507.67,"speaker_name":"bwillans"},{"text":"And I''m very excited because I do want to have those conversations.","index":200,"end_time":511.35,"speaker_id":1,"start_time":508.55,"speaker_name":"Colin Costigan"},{"text":"So we need to talk through, like, what offers we can make.","index":201,"end_time":514.07,"speaker_id":1,"start_time":511.43,"speaker_name":"Colin Costigan"},{"text":"What is the team, like, company willing to give for an Aquarius lead?","index":202,"end_time":518.39,"speaker_id":1,"start_time":514.07,"speaker_name":"Colin Costigan"},{"text":"Like, is there something free, cool, tangible that we can create and put out in these emails?","index":203,"end_time":523.11,"speaker_id":1,"start_time":518.39,"speaker_name":"Colin Costigan"},{"text":"Who are we going to be sending these to?","index":204,"end_time":524.93,"speaker_id":1,"start_time":523.11,"speaker_name":"Colin Costigan"},{"text":"Dive into all of that.","index":205,"end_time":525.81,"speaker_id":1,"start_time":524.93,"speaker_name":"Colin Costigan"},{"text":"Sounds great.","index":206,"end_time":527.17,"speaker_id":0,"start_time":526.61,"speaker_name":"bwillans"},{"text":"Yeah, we''re gonna.","index":207,"end_time":527.97,"speaker_id":0,"start_time":527.17,"speaker_name":"bwillans"},{"text":"Let''s start that next week.","index":208,"end_time":529.17,"speaker_id":0,"start_time":527.97,"speaker_name":"bwillans"},{"text":"We meet the two sales leads next.","index":209,"end_time":531.41,"speaker_id":0,"start_time":529.49,"speaker_name":"bwillans"},{"text":"Next week on abm.","index":210,"end_time":533.01,"speaker_id":0,"start_time":531.41,"speaker_name":"bwillans"},{"text":"So it''s kind of a chicken egg situation.","index":211,"end_time":535.73,"speaker_id":0,"start_time":533.65,"speaker_name":"bwillans"},{"text":"Right?","index":212,"end_time":536.05,"speaker_id":0,"start_time":535.73,"speaker_name":"bwillans"},{"text":"Like, do we start with you first?","index":213,"end_time":537.17,"speaker_id":0,"start_time":536.05,"speaker_name":"bwillans"},{"text":"But no, I.","index":214,"end_time":538.05,"speaker_id":0,"start_time":537.17,"speaker_name":"bwillans"},{"text":"We have those scheduled anyway, so we''re going to start those conversations and.","index":215,"end_time":541.33,"speaker_id":0,"start_time":538.13,"speaker_name":"bwillans"},{"text":"Perfect.","index":216,"end_time":542.13,"speaker_id":0,"start_time":541.65,"speaker_name":"bwillans"},{"text":"Yeah, it''s awesome, though.","index":217,"end_time":543.61,"speaker_id":0,"start_time":542.37,"speaker_name":"bwillans"},{"text":"It looks really, really good.","index":218,"end_time":544.65,"speaker_id":0,"start_time":543.61,"speaker_name":"bwillans"},{"text":"And I have no problem except for the fact that I just don''t think there''s enough padding in there, so.","index":219,"end_time":549.17,"speaker_id":0,"start_time":544.65,"speaker_name":"bwillans"},{"text":"Yeah, I gotcha.","index":220,"end_time":550.13,"speaker_id":1,"start_time":549.17,"speaker_name":"Colin Costigan"},{"text":"And here''s an update so you can see all of the checkboxes and everything that we''re importing in there are just.","index":221,"end_time":556.39,"speaker_id":1,"start_time":550.13,"speaker_name":"Colin Costigan"},{"text":"Because we''re doing, like, the.","index":222,"end_time":558.39,"speaker_id":1,"start_time":556.39,"speaker_name":"Colin Costigan"},{"text":"The opportunities.","index":223,"end_time":559.35,"speaker_id":1,"start_time":558.39,"speaker_name":"Colin Costigan"},{"text":"And there''s several opportunities tied to one contact.","index":224,"end_time":562.55,"speaker_id":1,"start_time":559.67,"speaker_name":"Colin Costigan"},{"text":"A few of the times.","index":225,"end_time":563.43,"speaker_id":1,"start_time":562.55,"speaker_name":"Colin Costigan"},{"text":"So.","index":226,"end_time":563.83,"speaker_id":1,"start_time":563.43,"speaker_name":"Colin Costigan"},{"text":"So we''re.","index":227,"end_time":566.07,"speaker_id":1,"start_time":565.43,"speaker_name":"Colin Costigan"},{"text":"We fix that.","index":228,"end_time":566.95,"speaker_id":1,"start_time":566.07,"speaker_name":"Colin Costigan"},{"text":"And then now it''s just, like, going through, like.","index":229,"end_time":569.07,"speaker_id":1,"start_time":566.95,"speaker_name":"Colin Costigan"},{"text":"All right, we need a property for pronouns.","index":230,"end_time":570.59,"speaker_id":1,"start_time":569.07,"speaker_name":"Colin Costigan"},{"text":"We need a property for gender identification.","index":231,"end_time":573.03,"speaker_id":1,"start_time":570.59,"speaker_name":"Colin Costigan"},{"text":"So all of this is being done and imported right now.","index":232,"end_time":576.43,"speaker_id":1,"start_time":574.23,"speaker_name":"Colin Costigan"},{"text":"So this is what I''ve been working on pretty much all the mornings.","index":233,"end_time":579.44,"speaker_id":1,"start_time":576.43,"speaker_name":"Colin Costigan"},{"text":"So appreciative.","index":234,"end_time":580.84,"speaker_id":0,"start_time":580.08,"speaker_name":"bwillans"},{"text":"Thanks.","index":235,"end_time":581.2,"speaker_id":0,"start_time":580.84,"speaker_name":"bwillans"},{"text":"And I just remembered one thing.","index":236,"end_time":583.52,"speaker_id":0,"start_time":581.36,"speaker_name":"bwillans"},{"text":"Thank you for the hawk ought lead form that was a huge hit in San Diego.","index":237,"end_time":589.6,"speaker_id":0,"start_time":584.16,"speaker_name":"bwillans"},{"text":"So appreciate that.","index":238,"end_time":590.56,"speaker_id":0,"start_time":589.6,"speaker_name":"bwillans"},{"text":"I have a question, and it''s ridiculous, but we did get a hawk lead come in.","index":239,"end_time":595.68,"speaker_id":0,"start_time":591.04,"speaker_name":"bwillans"},{"text":"And I''m going to meet with Blake.","index":240,"end_time":597.36,"speaker_id":0,"start_time":596.08,"speaker_name":"bwillans"},{"text":"He''s the BDR on Monday.","index":241,"end_time":598.6,"speaker_id":0,"start_time":597.36,"speaker_name":"bwillans"},{"text":"When he''s back.","index":242,"end_time":599.28,"speaker_id":0,"start_time":598.6,"speaker_name":"bwillans"},{"text":"Where does it go?","index":243,"end_time":601.2,"speaker_id":0,"start_time":600.08,"speaker_name":"bwillans"},{"text":"I don''t know.","index":244,"end_time":602.88,"speaker_id":0,"start_time":602,"speaker_name":"bwillans"},{"text":"It''s.","index":245,"end_time":604.16,"speaker_id":0,"start_time":603.6,"speaker_name":"bwillans"},{"text":"So we had a submission.","index":246,"end_time":606.7,"speaker_id":0,"start_time":604.9,"speaker_name":"bwillans"},{"text":"Yeah.","index":247,"end_time":607.14,"speaker_id":0,"start_time":606.7,"speaker_name":"bwillans"},{"text":"Does it go so, like, I. I don''t know that I gave you any mapping.","index":248,"end_time":611.14,"speaker_id":0,"start_time":607.14,"speaker_name":"bwillans"},{"text":"Like, if you look in there, there''s one that says Harry test.","index":249,"end_time":614.5,"speaker_id":0,"start_time":611.22,"speaker_name":"bwillans"},{"text":"That.","index":250,"end_time":614.98,"speaker_id":0,"start_time":614.58,"speaker_name":"bwillans"},{"text":"That is just a test, but there''s a real one in there.","index":251,"end_time":618.34,"speaker_id":0,"start_time":615.06,"speaker_name":"bwillans"},{"text":"A tool.","index":252,"end_time":619.74,"speaker_id":0,"start_time":619.3,"speaker_name":"bwillans"},{"text":"Yeah.","index":253,"end_time":620.26,"speaker_id":0,"start_time":619.74,"speaker_name":"bwillans"},{"text":"And I just.","index":254,"end_time":621.219,"speaker_id":0,"start_time":620.26,"speaker_name":"bwillans"},{"text":"Do I look like.","index":255,"end_time":622.46,"speaker_id":0,"start_time":621.54,"speaker_name":"bwillans"},{"text":"I feel like an idiot asking you this?","index":256,"end_time":624.1,"speaker_id":0,"start_time":622.46,"speaker_name":"bwillans"},{"text":"I should know where this goes.","index":257,"end_time":625.62,"speaker_id":0,"start_time":624.1,"speaker_name":"bwillans"},{"text":"I think.","index":258,"end_time":626.94,"speaker_id":1,"start_time":626.42,"speaker_name":"Colin Costigan"},{"text":"Yeah, I don''t think we did establish mapping for this one, did we?","index":259,"end_time":629.58,"speaker_id":1,"start_time":626.94,"speaker_name":"Colin Costigan"},{"text":"No, we didn''t.","index":260,"end_time":630.5,"speaker_id":0,"start_time":629.58,"speaker_name":"bwillans"},{"text":"So it''s okay, like, oh, it''s set.","index":261,"end_time":632.14,"speaker_id":0,"start_time":630.5,"speaker_name":"bwillans"},{"text":"To go to BDR at Aquatic, but they need to be a user in HubSpot.","index":262,"end_time":638.55,"speaker_id":1,"start_time":632.14,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":263,"end_time":639.35,"speaker_id":0,"start_time":638.95,"speaker_name":"bwillans"},{"text":"Okay.","index":264,"end_ti