ker_name":"Colin Costigan"},{"text":"I think so.","index":280,"end_time":666.96,"speaker_id":0,"start_time":666.36,"speaker_name":"bwillans"},{"text":"But we don''t know who.","index":281,"end_time":668.04,"speaker_id":0,"start_time":666.96,"speaker_name":"bwillans"},{"text":"Who set it up.","index":282,"end_time":670.12,"speaker_id":1,"start_time":669.24,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":283,"end_time":670.4,"speaker_id":0,"start_time":670.12,"speaker_name":"bwillans"},{"text":"Where.","index":284,"end_time":670.68,"speaker_id":1,"start_time":670.4,"speaker_name":"Colin Costigan"},{"text":"Where it came from.","index":285,"end_time":671.48,"speaker_id":1,"start_time":670.68,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":286,"end_time":671.88,"speaker_id":0,"start_time":671.48,"speaker_name":"bwillans"},{"text":"So.","index":287,"end_time":672.28,"speaker_id":2,"start_time":671.88,"speaker_name":"Guille Santana"},{"text":"So I''m going to.","index":288,"end_time":673.4,"speaker_id":0,"start_time":672.44,"speaker_name":"bwillans"},{"text":"What I''ll do.","index":289,"end_time":676.2,"speaker_id":0,"start_time":675.24,"speaker_name":"bwillans"},{"text":"I''ll send you an email, but I. I can set these guys up.","index":290,"end_time":678.6,"speaker_id":0,"start_time":676.2,"speaker_name":"bwillans"},{"text":"I''m going to set them up individually.","index":291,"end_time":680.16,"speaker_id":0,"start_time":678.68,"speaker_name":"bwillans"},{"text":"So I''m going to give.","index":292,"end_time":680.92,"speaker_id":0,"start_time":680.16,"speaker_name":"bwillans"},{"text":"Okay.","index":293,"end_time":681.4,"speaker_id":0,"start_time":680.92,"speaker_name":"bwillans"},{"text":"You know, let me set it up and I''ll send you guys an email.","index":294,"end_time":684.16,"speaker_id":0,"start_time":682.12,"speaker_name":"bwillans"},{"text":"It''ll be the three of them.","index":295,"end_time":685.56,"speaker_id":0,"start_time":684.16,"speake