-- Meeting: Aligned Growth Engine | Roadmap Meeting (2026-01-21 14:30:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '4aa1e0b0-c66a-4025-b0a2-2d1b998c8d99',
    '2026-01-21 14:30:00+00',
    'fireflies',
    '01KEYJNFJ5A480TR8EEP8XGTVE',
